// react-bot/src/App.js

import React, { Component } from 'react';
import Pusher from 'pusher-js';
import './App.css';
import {rubberBand} from 'animate.css';
import {fadeIn} from 'animate.css';

class App extends Component {
  constructor(props) {
    super(props);
    this.state = {
      userMessage: '',
      conversation: [],
    };
    this.res = this.res.bind(this);
  }

  res(obj, data, callback) {
    var xhttp = new XMLHttpRequest();
    var response;
    xhttp.onreadystatechange = function() {
      if (this.readyState === 4 && this.status === 200) {
        response = JSON.parse(xhttp.responseText);
        callback(obj, data, response);
      }
    };
    xhttp.open("GET", "recipes.json", true);
    xhttp.send();
  }

  componentDidMount() {
    document.title = "Chow Bot"
    const pusher = new Pusher('2ce112876c7564106cb3', {
      cluster: 'us3',
      encrypted: true,
    });

    const channel = pusher.subscribe('bot');
    channel.bind('bot-response', data => {
      const msg = {
        text: data.message,
        user: 'ai',
      };

      if (data.message.slice(0, 1) === "&") {
        var self = this;
        this.res(self, data, function(obj, data, response){
          var msg = "Here are some recipes for ";
          var ingred = data.message.slice(1);
          msg += ingred;
          msg += ": ";

          if (response.hasOwnProperty(ingred)) {
            for (var i = 0; i < response[ingred].length; i++) {
              var currRecipe = response[ingred][i];
              msg += currRecipe.link('https://www.messenger.com/');
              msg += ", ";
            }
            msg = msg.slice(0, msg.length - 2);
            console.log(msg);
            data.message = msg;
          } else {
            data.message = "Sorry I don't have a recipe for that in my database!";
          }
          msg = {
            text: data.message,
            user: 'ai',
          };
          console.log(obj);
          obj.setState({
            conversation: [msg, ...obj.state.conversation,],
          });
        });
      } else {
        this.setState({
          conversation: [msg, ...this.state.conversation,],
        });
      }

    });
  }

  handleChange = event => {
    this.setState({ userMessage: event.target.value });
  };

  handleSubmit = event => {
    event.preventDefault();
    if (!this.state.userMessage.trim()) return;

    const msg = {
      text: this.state.userMessage,
      user: 'human',
    };

    this.setState({
      conversation: [msg, ...this.state.conversation],
    });

    fetch('/chat', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        message: this.state.userMessage,
      }),
    });

    this.setState({ userMessage: '' });
  };

  render() {
    const ChatBubble = (text, i, className) => {
      return (
        <div key= {`${className}-${i}`} className={`${className} chat-bubble`}>
          <span className="chat-content" dangerouslySetInnerHTML = {{ __html: text}} />
        </div>
      );
    };

    const chat = this.state.conversation.map((e, index) =>
      ChatBubble(e.text, index, e.user)
    );

    return (
      <div>
        <div className="chat-window">
          <div className="animate__animated animate__rubberBand">
          <img
            src={require("./icons/chow.png")}
            alt="logo"
            height="97.5"
            width="88.5"
            className="logo"
          />
          </div>
          <div className="animate__animated animate__fadeIn">
            <div className="conversation-view">
              {chat}
            </div>
            <div className="message-box">
              <form onSubmit={this.handleSubmit}>
                <div className = "input-container">
                  <input
                    value={this.state.userMessage}
                    onChange={this.handleChange}
                    className="text-input"
                    type="text"
                    autoFocus
                    placeholder="Let's get cooking!"
                  />
                </div>
                <div className = "button-container">
                  <button type = "submit">
                  <p id = "send"> Send </p>
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      </div>
    );
  }
}

export default App;
